/**
 * Tests for stop/goal-convergence-emitter — M168 Phase 3 (#1913).
 *
 * Coverage:
 *   - emits `goal_converged` event + appends history line when
 *     `goal-current.json` declares status === 'converged';
 *   - idempotent: second call when history already has a close line
 *     for the same session is a no-op;
 *   - silent success when `goal-current.json` is missing;
 *   - silent success when status !== 'converged'.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import {
  existsSync,
  mkdirSync,
  mkdtempSync,
  readFileSync,
  rmSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { goalConvergenceEmitter } from '../../stop/goal-convergence-emitter.js';
import { readEventsSince } from '../../lib/event-log.js';
import { createTestContext } from '../fixtures/test-context.js';
import type { HookInput } from '../../types.js';

function stopInput(sid: string): HookInput {
  return {
    hook_event: 'Stop',
    tool_name: '',
    session_id: sid,
    tool_input: {},
  } as HookInput;
}

function writeGoalCurrent(projectDir: string, payload: Record<string, unknown>) {
  const dir = join(projectDir, '.claude', 'state');
  mkdirSync(dir, { recursive: true });
  writeFileSync(join(dir, 'goal-current.json'), JSON.stringify(payload));
}

function historyLines(projectDir: string): string[] {
  const path = join(projectDir, '.claude', 'state', 'goal-history.jsonl');
  if (!existsSync(path)) return [];
  return readFileSync(path, 'utf8').split('\n').filter(l => l.length > 0);
}

describe('stop/goal-convergence-emitter (#1913)', () => {
  let projectDir: string;
  let eventsDir: string;
  let eventsPath: string;
  let prevEventsEnv: string | undefined;

  beforeEach(() => {
    projectDir = mkdtempSync(join(tmpdir(), 'ork-gce-proj-'));
    eventsDir = mkdtempSync(join(tmpdir(), 'ork-gce-events-'));
    eventsPath = join(eventsDir, 'events.jsonl');
    prevEventsEnv = process.env.ORK_EVENTS_LOG;
    process.env.ORK_EVENTS_LOG = eventsPath;
  });

  afterEach(() => {
    if (prevEventsEnv === undefined) delete process.env.ORK_EVENTS_LOG;
    else process.env.ORK_EVENTS_LOG = prevEventsEnv;
    rmSync(projectDir, { recursive: true, force: true });
    rmSync(eventsDir, { recursive: true, force: true });
  });

  it('returns silent success when goal-current.json is missing', () => {
    const ctx = createTestContext({ projectDir, sessionId: 'sid-1' });
    const res = goalConvergenceEmitter(stopInput('sid-1'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(eventsPath)).toBe(false);
    expect(historyLines(projectDir)).toEqual([]);
  });

  it('returns silent success when status !== "converged"', () => {
    writeGoalCurrent(projectDir, {
      session_id: 'sid-pending',
      condition: 'tests pass',
      status: 'pending',
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-pending' });
    goalConvergenceEmitter(stopInput('sid-pending'), ctx);

    expect(existsSync(eventsPath)).toBe(false);
    expect(historyLines(projectDir)).toEqual([]);
  });

  it('emits goal_converged event + history line when converged', () => {
    writeGoalCurrent(projectDir, {
      session_id: 'sid-conv',
      condition: 'PR #1913 merged',
      status: 'converged',
      turn_count: 7,
      converged_at: '2026-05-22T10:00:00.000Z',
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-conv' });
    const res = goalConvergenceEmitter(stopInput('sid-conv'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });

    // Event log assertions.
    const events = readEventsSince(null);
    expect(events).toHaveLength(1);
    const ev = events[0];
    expect(ev.type).toBe('goal_converged');
    expect(ev.sid).toBe('sid-conv');
    if (ev.type === 'goal_converged') {
      expect(ev.condition).toBe('PR #1913 merged');
      expect(ev.status).toBe('converged');
      expect(ev.turn_count).toBe(7);
    }

    // History file assertions.
    const lines = historyLines(projectDir);
    expect(lines).toHaveLength(1);
    const closing = JSON.parse(lines[0]);
    expect(closing.session_id).toBe('sid-conv');
    expect(closing.status).toBe('converged');
    expect(closing.ended_at).toBe('2026-05-22T10:00:00.000Z');
    expect(closing.condition).toBe('PR #1913 merged');
    expect(closing.turn_count).toBe(7);
  });

  it('is idempotent — second call after history close does nothing', () => {
    writeGoalCurrent(projectDir, {
      session_id: 'sid-idem',
      condition: 'cond-1',
      status: 'converged',
      turn_count: 3,
      converged_at: '2026-05-22T11:00:00.000Z',
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-idem' });
    goalConvergenceEmitter(stopInput('sid-idem'), ctx);
    goalConvergenceEmitter(stopInput('sid-idem'), ctx);
    goalConvergenceEmitter(stopInput('sid-idem'), ctx);

    expect(readEventsSince(null)).toHaveLength(1);
    expect(historyLines(projectDir)).toHaveLength(1);
  });

  it('allows a new convergence after the prior history close belongs to a different session', () => {
    // Pre-seed a history close for a different session.
    const dir = join(projectDir, '.claude', 'state');
    mkdirSync(dir, { recursive: true });
    writeFileSync(
      join(dir, 'goal-history.jsonl'),
      `${JSON.stringify({ session_id: 'sid-other', ended_at: 't0', status: 'converged' })}\n`,
    );
    writeGoalCurrent(projectDir, {
      session_id: 'sid-new',
      condition: 'cond-new',
      status: 'converged',
      turn_count: 1,
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-new' });
    goalConvergenceEmitter(stopInput('sid-new'), ctx);

    expect(readEventsSince(null)).toHaveLength(1);
    const lines = historyLines(projectDir);
    expect(lines).toHaveLength(2);
    const lastClose = JSON.parse(lines[1]);
    expect(lastClose.session_id).toBe('sid-new');
    expect(lastClose.status).toBe('converged');
  });

  it('falls back to now() when goal-current lacks converged_at', () => {
    writeGoalCurrent(projectDir, {
      session_id: 'sid-noiso',
      status: 'converged',
      condition: 'cond',
      turn_count: 2,
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-noiso' });
    goalConvergenceEmitter(stopInput('sid-noiso'), ctx);

    const lines = historyLines(projectDir);
    expect(lines).toHaveLength(1);
    const closing = JSON.parse(lines[0]);
    // Just validate that it parses as a Date.
    expect(Number.isFinite(Date.parse(closing.ended_at))).toBe(true);
  });

  it('silent success when goal-current.json is malformed', () => {
    const dir = join(projectDir, '.claude', 'state');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, 'goal-current.json'), '{ broken');

    const ctx = createTestContext({ projectDir, sessionId: 'sid-bad' });
    const res = goalConvergenceEmitter(stopInput('sid-bad'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(eventsPath)).toBe(false);
    expect(historyLines(projectDir)).toEqual([]);
  });
});
